3	interface Item {
4	  type: string;
5	}
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  component: 30,
13	  rune: 30,
14	};
15	
16	const PROCESSING_FEES: Record<number, number> = {
17	  0: 0,
18	  1: 5,
19	  2: 10,
20	  3: 20,
21	};
22	
23	const calculateBasePremium = (items: Item[]): number => {
24	  return items.reduce(
25	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
26	    0
27	  );
28	};
29	
30	const getProcessingFee = (itemCount: number): number => {
31	  return PROCESSING_FEES[itemCount] ?? 5;
32	};
33	
34	export function quote(items: Item[]): number {
35	  if (items.length === 0) return 0;
36	
37	  // Building block rule: exactly 3 identical components get 60 G base premium
38	  if (items.length === 3 && items.every(item => item.type === "component")) {
39	    return 60;
40	  }
41	
42	  return calculateBasePremium(items) + getProcessingFee(items.length);
43	}
44	
